#[op2(fast)]
pub fn bsengine_get_tween_progress(#[string] name: String) -> f32 {
    TWEEN_SNAPSHOT.with(|s| {
        s.borrow()
            .get(&name)
            .map(|(_, d, _, _, el, _, _)| {
                if *d > 0.0 {
                    (el / d).clamp(0.0, 1.0)
                } else {
                    0.0
                }
            })
            .unwrap_or(0.0)
    })
}

