#[op2(fast)]
pub fn bsengine_get_beacon_remaining_fraction(#[string] name: String) -> f32 {
    BEACON_SNAPSHOT.with(|s| {
        s.borrow()
            .get(&name)
            .map(|(_, _, dur, timer, lit, _, _, _)| {
                if !*lit {
                    0.0
                } else if *dur <= 0.0 {
                    1.0
                } else {
                    (*timer / *dur).clamp(0.0, 1.0)
                }
            })
            .unwrap_or(0.0)
    })
}

